catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
	if (isLoading || newValue == '') {
		return;
	}

	/*
	  申請区分の値に応じた項目の活性化/非活性化
	*/
	if (g_form.getValue("work_app_type") === "有給休暇（終日）"){
		// 有給休暇（終日）
		setActive("is_cordinated");
		setActive("target_date");

		setInactive("start_time");
		setInactive("end_time");
		setInactive("worked_day");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");

	} else if (g_form.getValue("work_app_type") === "有給休暇（時間単位）") {
		// 有給休暇（時間単位）
		setActive("is_cordinated");
		setActive("target_date");
		setActive("start_time");
		setActive("end_time");

		setInactive("worked_day");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	} else if (g_form.getValue("work_app_type") === "有給休暇（健康診断）") {
		// 有給休暇（健康診断）
		setActive("is_cordinated");
		setActive("target_date");

		setInactive("start_time");
		setInactive("end_time");
		setInactive("worked_day");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	}else if (g_form.getValue("work_app_type") === "特別休暇（夏休）") {
		// 特別休暇（夏休）
		setActive("is_cordinated");
		setActive("target_date");

		setInactive("start_time");
		setInactive("end_time");
		setInactive("worked_day");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	}else if (g_form.getValue("work_app_type") === "特別休暇（PRJ）") {
		// 特別休暇（PRJ）
		setActive("is_cordinated");
		setActive("target_date");

		setInactive("start_time");
		setInactive("end_time");
		setInactive("worked_day");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	}else if (g_form.getValue("work_app_type") === "特別休暇（慶弔）") {
		// 特別休暇（慶弔）
		setActive("is_cordinated");
		setActive("target_date");

		setInactive("start_time");
		setInactive("end_time");
		setInactive("worked_day");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	}else if (g_form.getValue("work_app_type") === "振替休日") {
		// 振替休日
		setActive("is_cordinated");
		setActive("target_date");
		setActive("worked_day");

		setInactive("start_time");
		setInactive("end_time");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	}else if (g_form.getValue("work_app_type") === "代休") {
		// 代休
		setActive("is_cordinated");
		setActive("target_date");
		setActive("worked_day");

		setInactive("start_time");
		setInactive("end_time");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	}else if (g_form.getValue("work_app_type") === "深夜勤務") {
		// 深夜勤務
		setActive("is_cordinated");
		setActive("worked_day");
		setActive("start_working_time");
		setActive("end_working_time");

		setInactive("target_date");
		setInactive("start_time");
		setInactive("end_time");
		setInactive("working_day");
		setInactive("replacement_holiday");
	}else if (g_form.getValue("work_app_type") === "休日振替出勤") {
		// 休日振替出勤
		setActive("is_cordinated");
		setActive("start_time");
		setActive("end_time");
		setActive("working_day");
		setActive("replacement_holiday");

		setInactive("worked_day");
		setInactive("start_working_time");
		setInactive("end_working_time");
		setInactive("target_date");
	}



}

// 対象フィールドの非活性化
function setInactive(field_name) {
	g_form.setMandatory(field_name, false);
	g_form.setDisplay(field_name, false);
}

// 対象フィールドの活性化
function setActive(field_name) {
	g_form.setDisplay(field_name, true);
	g_form.setMandatory(field_name, true);
}
